insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hokkaido' and m.slug = 'sapporo'), 'hokkaido-sapporo-elderly-diapers', '札幌市 高齢者等紙おむつサービス事業（在宅要介護高齢者向け紙おむつ宅配サービス）', '札幌市が実施する地域支援事業の一環として、在宅で重度の要介護状態にある高齢者に対し、月1回、上限額の範囲内で紙おむつを自宅に宅配する現物支給サービス。公式サイトで確認できる制度として整理した。', NULL, 'service', '札幌市内に居住し住民票がある在宅の40歳以上の要介護認定者のうち、要介護4〜5で認定調査票の排尿または排便の項目が全介助となっている方、または要介護3で認知症高齢者の日常生活自立度がIII以上かつ排尿または排便が全介助となっている方が対象となる可能性があります。詳細な該当基準は公式サイト・区役所窓口でご確認ください。', '月1回、上限額（公式サイト上の記載では6,500円程度）の範囲内で紙おむつが宅配される現物支給。利用者負担はかかる費用の1割相当額（生活保護受給世帯は無料の場合あり）とされていますが、年度により金額・負担割合が変更される可能性があるため、最新情報は公式サイトまたは区役所でご確認ください。', '随時受付と見られますが、公式サイト・区役所で確認が必要です。', '居住する区の区役所保健福祉課へ申請します。詳細な必要書類・手続きの流れは区役所窓口または公式サイトでご確認ください。', '介護保険被保険者証など要介護認定の状況が確認できる書類が必要になる可能性がありますが、詳細は区役所へご確認ください。', FALSE, NULL, NULL, 'https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html', 'https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html', '介護保険サービス以外に札幌市が行っている高齢者支援（地域支援事業など）／札幌市', '2026-07-01', 'medium', ARRAY['benefitAmountText（上限額6,500円の最新性・年度改定の有無）', 'targetPeople（要介護度・自立度基準の詳細区分と最新性）', 'requiredDocumentsText（必要書類の具体的リスト）', 'applicationDeadlineText（受付期間・随時性の確認）', '重度障がい者(児)向けの別制度（omutuyouryo202504.pdf）との関係・対象範囲の重複有無']::text[], '本情報は公式サイトの記載を基にした概括であり、対象要件・給付上限額・自己負担割合等は年度や個別状況により異なる場合があります。申請可否や支給額を保証するものではありません。最新かつ正確な情報は、居住区の区役所保健福祉課または札幌市公式サイトで必ずご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'hokkaido-sapporo-elderly-diapers' and c.slug = 'nursing-care' on conflict do nothing;
insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'hokkaido-sapporo-elderly-diapers' and le.slug = 'caregiving' on conflict do nothing;
insert into public.support_program_topics (support_program_id, support_topic_id) select sp.id, t.id from public.support_programs sp, public.support_topics t where sp.slug = 'hokkaido-sapporo-elderly-diapers' and t.slug = 'elderly-diapers' on conflict do nothing;
insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"hokkaido-sapporo-elderly-diapers","status":"published","title":"札幌市 高齢者等紙おむつサービス事業（在宅要介護高齢者向け紙おむつ宅配サービス）","officialUrl":"https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html","topic":"elderly-diapers"}'::jsonb, 'pilot:hokkaido-sapporo-elderly-diapers:aG9ra2FpZG8tc2FwcG9yby1lbGRlcmx5LWRpYXBl' from public.support_programs sp where sp.slug='hokkaido-sapporo-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'miyagi' and m.slug = 'sendai'), 'miyagi-sendai-elderly-diapers', '仙台市 介護用品の給付（紙おむつ等）', '仙台市が実施する在宅の要介護高齢者向け介護用品給付事業。要介護4または5の認定を受け、市民税非課税世帯に該当する方を対象に、使い捨ておむつ・おむつカバー・尿とりパッド・失禁シーツ等を事業者が自宅へお届けする現物給付制度です（公式サイトで詳細確認が必要な場合があります）。', NULL, 'service', '在宅で生活し、介護保険の要介護4または5の認定を受けている方のうち、市民税非課税世帯に該当する可能性がある方が対象となる可能性があります（入院中の方・生活保護受給者等は対象外の場合があります）。詳細な要件は公式サイトでご確認ください。', '年間（4月～翌年3月）7万5千円が利用限度額とされていますが、申込時期により限度額が異なる場合があるとのことです。正確な金額は公式サイトまたは区役所窓口でご確認ください。', '随時受付とみられますが、公式サイトで明確な期限の記載は確認できませんでした。年度（4月～翌年3月）単位での利用限度額管理のため、年度内の申請時期により限度額が変わる可能性があるとのことです。', 'お住まいの区の区役所・総合支所担当課窓口で申請するとされています。オンライン申請の可否は公式サイトでは明確に確認できませんでした。', '介護保険被保険者証の写し、市民税非課税世帯であることを証明する資料（介護保険料決定通知書の写し等）が必要とされています（申請者の同意により一部省略できる場合があるとのこと）。', FALSE, '仙台市健康福祉局高齢企画課', '022-214-8168', 'https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/zaitaku/fukushi/kaigoyohin.html', 'https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/zaitaku/fukushi/kaigoyohin.html', '介護用品の給付｜仙台市', '2026-07-01', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople', 'onlineApplicationAvailable']::text[], '本情報は2026年7月1日時点で仙台市公式サイトを確認した内容に基づく概括です。所得要件・支給額・対象範囲等の詳細や最新の制度内容は、必ず仙台市公式サイトまたは各区役所窓口でご確認ください。本制度の利用を保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
