insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"miyagi-sendai-elderly-diapers","status":"published","title":"仙台市 介護用品の給付（紙おむつ等）","officialUrl":"https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/zaitaku/fukushi/kaigoyohin.html","topic":"elderly-diapers"}'::jsonb, 'pilot:miyagi-sendai-elderly-diapers:bWl5YWdpLXNlbmRhaS1lbGRlcmx5LWRpYXBlcnN8' from public.support_programs sp where sp.slug='miyagi-sendai-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'saitama' and m.slug = 'saitama'), 'saitama-saitama-elderly-diapers', '重度要介護高齢者紙おむつ等支給事業（さいたま市）', 'さいたま市が、在宅で常時おむつを使用する重度要介護高齢者（要介護3〜5等の要件を満たす方）に対し、月額6,000円（税込）を上限とする紙おむつ・尿とりパッド等の利用券を年間最大12枚支給する市独自の事業です。詳細な対象要件・金額・手続きは公式ページで確認できます。', NULL, 'service', 'さいたま市内に住み、在宅で常時紙おむつを使用している65歳以上の高齢者のうち、介護保険の要介護度が3・4・5のいずれかに該当し（要介護3の場合は排尿・排便に介助等を要すること等の追加要件あり）、所得段階・保険料納付状況・施設入所状況などの条件を満たす方が対象となる可能性があります。詳細は公式ページ・区役所高齢介護課で確認してください。', '月額6,000円（税込）を限度額とする紙おむつ等の利用券を、年間最大12枚支給（超過分は自己負担となる可能性があります）。', '毎月24日（土日祝の場合は直前の開庁日）17時15分までに不備なく申請することが必要とされています（詳細は公式で確認）。', 'お住まいの区の高齢介護課高齢福祉係へ「高齢者福祉総合申請書」等の申請書類を提出します。毎月の締切（24日または直前の開庁日17時15分まで）があり、電子申請にも対応している場合があります。詳細は公式ページ・各区高齢介護課で確認してください。', '高齢者福祉総合申請書（様式は公式ページからダウンロード可能、Word・PDF形式）。その他、要介護度や所得段階等を確認できる書類の提出・確認が求められる可能性があります（公式で要確認）。', TRUE, 'さいたま市福祉局長寿応援部高齢福祉課（申請自体は各区役所高齢介護課高齢福祉係）', '048-829-1260', 'https://www.city.saitama.lg.jp/002/003/003/002/005/p064031.html', 'https://www.city.saitama.lg.jp/002/003/003/002/005/p064031.html', '重度要介護高齢者紙おむつ等支給事業 - さいたま市', '2026-07-01', 'high', ARRAY['所得段階（第1〜5段階）の具体的な区分と判定方法', '要介護3の場合の排尿・排便の介助等該当基準の詳細', '月6,000円超過分の自己負担の具体的な扱い', '電子申請の対象範囲・利用可否の詳細', '区ごとの窓口対応や手続きの細かな差異']::text[], '本情報は公式ページの内容を基にした概括であり、必ず受給できることを保証するものではありません。所得段階・要介護度・保険料納付状況等の詳細要件、支給上限超過時の自己負担、電子申請の可否等は各区高齢介護課または公式ページで最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
