insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"saitama-saitama-elderly-diapers","status":"published","title":"重度要介護高齢者紙おむつ等支給事業（さいたま市）","officialUrl":"https://www.city.saitama.lg.jp/002/003/003/002/005/p064031.html","topic":"elderly-diapers"}'::jsonb, 'pilot:saitama-saitama-elderly-diapers:c2FpdGFtYS1zYWl0YW1hLWVsZGVybHktZGlhcGVy' from public.support_programs sp where sp.slug='saitama-saitama-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'chiba' and m.slug = 'chiba'), 'chiba-chiba-elderly-diapers', '千葉市 おむつ給付等事業（高齢者）', '千葉市では、在宅で要介護1〜5の認定を受け常時失禁状態にある高齢者を対象に、紙おむつ費用の一部を助成する「おむつ給付等事業」を実施しています。要介護1〜3は月額基準4,000円、要介護4〜5は月額基準8,000円のうち、市が9割・利用者が1割を負担する仕組みです（実際の購入費が基準額より低い場合はその9割を給付）。対象は本人および同一住所の親族全員が市民税非課税であることなど所得要件があり、生活保護受給者は対象外です。なお千葉市は別途、在宅の重度心身障害者（身体障害者手帳1・2級等）を対象とした「おむつ給付」制度も設けており、こちらは月額基準8,000円（市9割・利用者1割）です。詳細な支給枚数・単価・所得基準は公式サイトや各区高齢障害支援課で必ず確認してください。', NULL, 'subsidy', '在宅で要介護1〜5の認定を受け常時失禁状態にある千葉市内居住の高齢者（本人および同一住所の親族全員が市民税非課税である場合が対象となる可能性）。別途、身体障害者手帳1・2級等の在宅重度心身障害者向けの類似制度もあります。', '要介護1〜3：月額基準4,000円（市9割負担・利用者1割負担）、要介護4〜5：月額基準8,000円（市9割負担・利用者1割負担）。実際の購入費が基準額より低い場合はその9割を給付（重度障害者向け制度は月額基準8,000円・同比率）。金額・支給内容は変更される場合があるため公式サイトで要確認。', '随時受付（公式サイトに具体的な締切の記載は確認できず）。', '指定納入業者と相談し「配達相談連絡票」等を受け取った上で、申請書・調査同意書・介護保険被保険者証の写し等の必要書類をお住まいの区の保健福祉センター高齢障害支援課（重度障害者向けは障害者自立支援課とも関連）に提出。審査後、給付決定通知を受け取り、以降は業者から毎月配達され、受け取り時に自己負担分を支払う方式。オンライン申請の可否は公式サイトで要確認。', '申請書（様式第1号）、調査同意書（様式第1号の2）、配達相談連絡票（様式第2号）、介護保険被保険者証の写し、必要に応じて課税状況確認書類・生計申立書等（詳細は公式サイト・窓口で要確認）。', FALSE, '千葉市 各区保健福祉センター高齢障害支援課（例：中央保健福祉センター）／重度障害者向けは保健福祉局高齢障害部障害者自立支援課', '043-221-2150（中央保健福祉センター）／043-245-5173（障害者自立支援課）', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/diaper.html', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/diaper.html', '千葉市：おむつ給付等事業（高齢者）', '2026-07-01', 'high', ARRAY['benefitAmountText（実際の支給枚数・単価・所得基準の詳細は公式サイト・窓口で要確認）', 'applicationDeadlineText（具体的な受付締切の記載は確認できず、随時受付と推測）', 'targetPeople（重度障害者向け制度との対象区分の詳細は公式サイトで要確認）', 'onlineApplicationAvailable（オンライン申請可否の明記は確認できず）']::text[], '本情報は2026年7月時点の千葉市公式サイトの記載に基づく概括です。所得要件・支給額・対象要件等の詳細、および最新の制度内容は必ず千葉市公式サイトまたは窓口でご確認ください。申請すれば必ず受給できるとは限らず、審査により対象外となる場合があります。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
