insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'kawasaki'), 'kanagawa-kawasaki-elderly-diapers', '川崎市 紙おむつ等介護用品の給付', '川崎市が在宅の要介護高齢者等を対象に、紙おむつ類・おむつカバー・防水シーツ・使い捨て手袋・消臭剤・清拭剤・ドライシャンプーなどの介護用品を月1回、限度額の範囲内で給付する制度です。市内共通の事業として各区役所高齢・障害課が窓口となります。', NULL, 'service', '在宅で生活する65歳以上の高齢者のうち介護保険の要介護認定が要介護3～5の方、および40～64歳で要介護3～5かつ介護保険法上の特定疾病「初老期における認知症」相当と認定された方が対象となる可能性があります（施設入所者・長期入院者等は対象外の可能性）。詳細は公式で確認してください。', '給付限度額は月額6,000円（令和8年4月改定後、一般利用者の場合）。生活保護受給世帯等は月額3,000円（この場合、紙おむつ類・おむつカバーは給付対象外）。利用者負担は所得等に応じて限度額の0%～20%程度（生活保護世帯0%、市町村民税非課税世帯等5%、本人非課税10%、本人課税20%など段階あり）とされています。金額・負担率・対象品目は変更される場合があるため、必ず公式最新情報でご確認ください。', '', '各区役所の高齢・障害課（高齢者支援）窓口での申請、またはオンライン手続き（e-KAWASAKIなど）での申請が案内されています。申請様式として「高齢者在宅サービス利用申出書」等が用意されています。詳細な必要書類・手続きの流れは公式ページまたは窓口でご確認ください。', '高齢者在宅サービス利用申出書（共通第1号様式）など。要介護認定を確認できる書類等が必要となる可能性があります。詳細は公式でご確認ください。', TRUE, '川崎市健康福祉局高齢者在宅サービス課', '044-200-2911（または044-200-2677）', 'https://www.city.kawasaki.jp/350/page/0000022608.html', 'https://www.city.kawasaki.jp/350/page/0000022608.html', '川崎市：紙おむつ等介護用品の給付', '2026-07-01', 'high', ARRAY['benefitAmountText（令和8年4月の増額改定前後で金額表記に幅あり。ページ間で6,000円/3,000円等の記載差異を確認）', 'requiredDocumentsText（要綱ページに複数様式があり詳細未確認）', 'targetPeople（施設入所者等の除外条件の細部）', 'applicationDeadlineText（随時申請と推定されるが公式に明記なし）']::text[], '本情報は公式サイトの記載に基づく概括であり、対象要件・給付額・負担率は所得や状況により異なります。必ず川崎市公式サイトまたは各区役所窓口で最新の詳細をご確認ください。申請すれば必ず受給できることを保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
