insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"kanagawa-kawasaki-elderly-diapers","status":"published","title":"川崎市 紙おむつ等介護用品の給付","officialUrl":"https://www.city.kawasaki.jp/350/page/0000022608.html","topic":"elderly-diapers"}'::jsonb, 'pilot:kanagawa-kawasaki-elderly-diapers:a2FuYWdhd2Eta2F3YXNha2ktZWxkZXJseS1kaWFw' from public.support_programs sp where sp.slug='kanagawa-kawasaki-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'sagamihara'), 'kanagawa-sagamihara-elderly-diapers', '紙おむつ等の支給（相模原市）', '相模原市が在宅の高齢者・障害者を対象に、紙おむつ等を現物支給する制度です。60歳以上で要介護4・5の在宅ねたきり高齢者や認知症高齢者、身体障害者手帳・療育手帳をお持ちの在宅障害者などが対象となる可能性があります。世帯の課税状況により対象外となる場合があります。年6回、申請に基づき無料で支給されます。', NULL, 'service', '在宅で生活保護制度を利用していない人のうち、(1)60歳以上の在宅ねたきり高齢者（要介護4・5相当）または紙おむつ等を必要とする認知症高齢者、(2)身体障害者手帳または療育手帳を所有する在宅障害者、のいずれかに該当する人が対象となる可能性があります（詳細は公式で要確認）。本人及び本人の属する世帯に市民税課税者がいる場合は対象外となります（均等割のみ課税の扱いは公式で要確認）。', '紙おむつ・尿とりパッド等の現物支給（パンツ型・フラット型・テープ型・子供用テープ型・尿とりパッドなど）。利用料は無料。支給量・上限は公式で要確認。', '支給希望月の前月末日（年6回：5・7・9・11・1・3月分）', '居住地域を担当する高齢・障害者相談課等（緑区・中央区・南区の各相談窓口、城山・津久井・相模湖・藤野地域は個別窓口）へ申請書を提出してください。支給は年6回（5・7・9・11・1・3月）で、支給希望月の前月末日が申請締め切りとされています。窓口・提出書類の詳細は公式サイトで確認してください。', '申請書ほか、公式サイトまたは窓口で要確認（要介護認定・手帳等の状況により異なる可能性があります）', FALSE, '相模原市 高齢・障害者支援課（居住区により窓口が異なります）', '042-769-9249', 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006388.html', 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006388.html', '紙おむつ等の支給｜相模原市', '2026-07-01', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は公式サイトの記載を要約したものです。対象要件・所得制限（均等割のみ課税の扱い含む）・支給量・最新の手続きは必ず相模原市公式サイトまたは窓口でご確認ください。制度は変更される場合があります。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
