insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"kanagawa-sagamihara-elderly-diapers","status":"published","title":"紙おむつ等の支給（相模原市）","officialUrl":"https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006388.html","topic":"elderly-diapers"}'::jsonb, 'pilot:kanagawa-sagamihara-elderly-diapers:a2FuYWdhd2Etc2FnYW1paGFyYS1lbGRlcmx5LWRp' from public.support_programs sp where sp.slug='kanagawa-sagamihara-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'niigata' and m.slug = 'niigata'), 'niigata-niigata-elderly-diapers', '新潟市紙おむつ支給事業', '新潟市が実施する在宅の高齢要介護者向けの紙おむつ支給事業。常時おむつを必要とする40歳以上の要介護認定者のうち、身体要件・所得要件を満たす方を対象に、介護度や課税段階に応じた枚数の紙おむつ（パンツ型または平型）を現物支給する制度です。', NULL, 'service', '常時おむつを必要とする在宅の40歳以上の要介護認定者（第1号・第2号被保険者）で、要介護1〜5かつ障がい高齢者の日常生活自立度がB以上またはアルツハイマー型認知症の日常生活自立度が3以上に該当し、かつ市民税本人非課税（介護保険料段階1〜5）である方が対象となる可能性があります。詳細は公式サイト・各区役所窓口で確認してください。', '世帯の課税状況と要介護度に応じて支給枚数が異なります。目安として、非課税世帯（保険料段階1〜3）で要介護1〜3はパンツ型60枚または平型200枚相当、要介護4〜5はパンツ型90枚または平型300枚相当、本人非課税（段階4・5）で要介護1〜5はパンツ型30枚または平型100枚相当とされています（公式サイト記載時点、最終更新2021年2月10日）。最新の内容は公式サイトまたは区役所窓口で確認してください。', '常時受付と考えられますが、公式サイトに明記なし。詳細は区役所窓口で確認してください。', '公式サイト本文には申請方法の詳細記載がありません。各区役所健康福祉課高齢介護担当、または新潟市福祉部高齢者支援課（電話：025-226-1295）に問い合わせることで案内を受けられます。', '公式サイトに明記なし。申請時の必要書類は各区役所健康福祉課高齢介護担当に確認してください。', FALSE, '新潟市福祉部高齢者支援課（または各区役所健康福祉課高齢介護担当）', '025-226-1295', 'https://www.city.niigata.lg.jp/iryo/korei/zaitakukaigo/kamiomutsu.html', 'https://www.city.niigata.lg.jp/iryo/korei/zaitakukaigo/kamiomutsu.html', '紙おむつ支給事業 - 新潟市', '2026-07-01', 'medium', ARRAY['benefitAmountText', 'targetPeople', 'applicationMethodText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は公式サイト記載内容（最終更新2021年2月10日）に基づく概括であり、支給の可否・枚数・所得要件等は個別の状況により異なります。必ず新潟市公式サイトまたは各区役所窓口で最新情報をご確認ください。申請すれば必ず支給されることを保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
