insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"niigata-niigata-elderly-diapers","status":"published","title":"新潟市紙おむつ支給事業","officialUrl":"https://www.city.niigata.lg.jp/iryo/korei/zaitakukaigo/kamiomutsu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:niigata-niigata-elderly-diapers:bmlpZ2F0YS1uaWlnYXRhLWVsZGVybHktZGlhcGVy' from public.support_programs sp where sp.slug='niigata-niigata-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'shizuoka'), 'shizuoka-shizuoka-elderly-diapers', '静岡市高齢者紙おむつ支給制度', '静岡市が、在宅で生活する高齢者のうち要介護度や所得等の条件を満たす方を対象に、紙おむつと引き換えられる引換券を支給する市独自の制度です。要介護度に応じて月額の支給額（引換券の額面）が異なります。', NULL, 'service', '月の半分以上を自宅で生活している65歳以上で紙おむつを必要とする方のうち、(1)生活保護世帯またはすべての世帯員が市民税非課税である世帯に属し、(2)要介護4・5の認定を受けているか、要介護1〜3で特に紙おむつが必要と認められ、(3)障害者支援課で紙おむつ券を受給していない方が対象となる可能性があります。詳細な要件は公式サイトまたは各区高齢介護課で必ずご確認ください。', '要介護度に応じて紙おむつ引換券を月額支給（公式サイトの記載に基づく概算）：要介護1・2は月1,500円分、要介護3は月5,500円分、要介護4は月6,000円分、要介護5は月6,500円分。金額や算定基準は変更される可能性があるため、必ず公式サイトまたは窓口で最新情報を確認してください。', '随時受付（公式サイトの記載に基づくが、年度ごとの運用や具体的な申請期限が設けられている可能性があるため、必ず窓口または公式サイトで最新の締切情報を確認してください）', '窓口申請または電子申請（静岡市公式サイトの案内による）。申請窓口は葵区高齢介護課、駿河区高齢介護課、清水区高齢介護課、蒲原出張所。新規申請時は申請書・同意書等の提出が必要です。', '認め印（スタンプ印不可）、本人確認書類（介護保険被保険者証等）、新規申請時は申請書・同意書。詳細は公式サイトまたは窓口で確認してください。', TRUE, '静岡市保健福祉長寿局健康福祉部高齢者福祉課', '054-221-1201（高齢者福祉課）／葵区高齢介護課 054-221-1089／駿河区高齢介護課 054-287-8678／清水区高齢介護課 054-354-2162／蒲原出張所 054-385-7790', 'https://www.city.shizuoka.lg.jp/s2837/s002726.html', 'https://www.city.shizuoka.lg.jp/s2837/s002726.html', '高齢者紙おむつ支給制度：静岡市公式ホームページ', '2026-07-01', 'high', ARRAY['applicationDeadlineText（随時受付か年度ごとの申請期限があるか、情報源間で記載に差異があり確定できず）', '要介護1〜3で「特に紙おむつが必要と認められる」の具体的な判定基準', 'onlineApplicationAvailableの電子申請の具体的な対象範囲']::text[], '本情報は静岡市公式サイトの記載内容の概括であり、支給を保証するものではありません。対象要件・支給額・手続きの詳細、申請期限は変更されることがあるため、必ず静岡市公式サイトまたは各区高齢介護課で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
