insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'hamamatsu'), 'shizuoka-hamamatsu-elderly-diapers', '紙おむつ等の支給（浜松市）', '浜松市が在宅で要介護4・5の高齢者を介護する市民税非課税世帯を対象に、紙おむつ等の衛生用品を年間6万円分を上限に現物支給する制度です。あわせて浜松市には重度障害者（児）向けの紙おむつ購入費助成（年間3万円上限、公式URL: https://www.city.hamamatsu.shizuoka.jp/syoghuku/welfare/obstacle/contents/kamiomutu.html）という別制度も公式に存在することが確認できます。', '浜松市には在宅で要介護4・5の高齢者を介護している市民税非課税世帯向けに、紙おむつなどを年間6万円分まで無料で支給する制度があります。また、重度障害のある方（児）向けには紙おむつ購入費を年間3万円まで助成する別の制度も浜松市にあります。どちらも詳しい条件や申請方法は浜松市公式サイトまたは福祉事業所でご確認ください。', 'service', '65歳以上で要介護4または5の認定を受け、在宅で介護されている方のうち、介護者・被介護者双方が市民税非課税世帯に属する方が対象となる可能性があります。他制度で同様のサービスを受けていないことも条件とされています。詳細は公式サイトでご確認ください。', '年間（4月〜翌年3月）で60,000円分を上限に、紙おむつ（フラット・テープ止め・パンツ・パッドタイプ）、おしりふき、使い捨て手袋、一部医療用品（吸引カテーテル、ガーゼ、ドレーンバックなど）を現物支給するとされています。金額・対象品目は公式サイトで要確認です。', '紙おむつ類は毎年度2月末頃、医療用品は毎年度1月末頃までとされています（年度により変動する可能性があるため公式で要確認）。', 'ケアマネジャーを通じて、または同居親族が直接、各福祉事業所（中央・浜名・天竜）の窓口で申請するとされています。紙おむつ類は毎年度2月末頃、医療用品は毎年度1月末頃までに申請が必要とされています（年度により変更の可能性があります）。', '公式ページに具体的な必要書類の明記は確認できませんでした。申請時は各福祉事業所またはケアマネジャーにご確認ください。', FALSE, '浜松市 高齢者相談センター／各福祉事業所（中央・浜名・天竜）', '', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/omutsu.html', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/omutsu.html', '紙おむつ等の支給／浜松市', '2026-07-01', 'high', ARRAY['targetPeople（要介護度・所得条件の詳細な運用基準）', 'benefitAmountText（対象品目の詳細な内訳や年度ごとの上限額変更の有無）', 'requiredDocumentsText（申請時の具体的必要書類）', 'applicationDeadlineText（申請期限は年度により変動する可能性）', '重度障害者（児）向けの別制度（紙おむつ購入費助成、年間3万円上限）が浜松市に別途存在するが、本レコードには含めていない']::text[], '本情報は公式サイトの内容を要約したものであり、対象条件・金額・申請方法は年度により変更される場合があります。必ず浜松市公式サイトまたは担当窓口で最新情報をご確認ください。申請すれば必ず支給されることを保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
