insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"shizuoka-hamamatsu-elderly-diapers","status":"published","title":"紙おむつ等の支給（浜松市）","officialUrl":"https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/omutsu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:shizuoka-hamamatsu-elderly-diapers:c2hpenVva2EtaGFtYW1hdHN1LWVsZGVybHktZGlh' from public.support_programs sp where sp.slug='shizuoka-hamamatsu-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'aichi' and m.slug = 'nagoya'), 'aichi-nagoya-elderly-diapers', '日常生活用具の給付（紙おむつ等）', '名古屋市が実施する障害児・者向け日常生活用具給付制度の対象種目の一つとして「紙おむつ等」が含まれています。ぼうこう機能障害・直腸機能障害（人工肛門・人工膀胱等のストーマ造設者で装具装着が困難な方等）や、一定の要件を満たす肢体不自由（脳原性運動機能障害）のある方が対象となる可能性があります。要介護度のみを基準とする一般的な高齢者向けおむつ支給とは異なり、障害福祉制度の枠内での給付である点に注意が必要です。給付を希望する用具・障害の内容により申請に必要な書類が異なるため、事前にお住まいの区の区役所福祉課へご相談ください。', NULL, 'service', '名古屋市内在住で、ぼうこう機能障害または直腸機能障害（ストーマ造設等）があり、治療による軽快が見込めずストーマ用装具の装着が困難な方、先天性疾患に起因する高度の排尿・排便機能障害がある方、または脳原性運動機能障害により排尿・排便の意思表示が困難な肢体不自由の方（発現年齢6歳未満・申請時3歳以上等の要件あり）が対象となる可能性があります。年齢や等級等の具体的要件は公式資料でご確認ください。', '種目ごとに給付限度額が設定されており、購入費の1割相当額を上限月額まで利用者が負担します（「紙おむつ等」自体の給付基準額・耐用年数は一覧表に金額記載なし）。詳細な金額は公式資料・区役所窓口で要確認。', '', '用具を購入する前に、お住まいの区の区役所福祉課（社会福祉事務所）または支所区民福祉課へ事前相談・申請が必要です。用具と障害の内容により必要書類が異なります。利用者本人（児童の場合は保護者）の市民税所得割の額が46万円以上の場合は原則対象外（対象者が障害児の場合を除く）。給付には所得に応じた利用者負担（上限月額まで販売価格の1割）があります。', '用具・障害の内容により異なるため、事前に区役所福祉課へ要確認。', FALSE, '名古屋市 各区役所福祉課（社会福祉事務所）・支所区民福祉課', '', 'https://www.kaigo-wel.city.nagoya.jp/view/wel/shiori/zaitaku/nichijyohin.html', 'https://www.kaigo-wel.city.nagoya.jp/view/wel/shiori/zaitaku/nichijyohin.html', '日常生活用具の給付 - 介護・障害情報提供システム（ウェルネットなごや）｜名古屋市', '2026-07-01', 'medium', ARRAY['targetPeople（詳細な障害等級・年齢要件は種目一覧PDFの原文条件を必ず参照）', 'benefitAmountText（紙おむつ等の具体的な給付基準額・限度額は一覧表に金額記載なし、区役所で要確認）', '本制度が高齢者向け『在宅要介護高齢者紙おむつ支給事業』に相当する別制度の有無は今回未確認（見当たらなかった）']::text[], '本制度は障害福祉分野の「日常生活用具給付」の対象種目の一つとして紙おむつ等が含まれるものであり、要介護度のみを基準とする一般的な在宅高齢者向けのおむつ支給事業ではありません。対象となるか、支給内容・自己負担額の詳細は、必ず名古屋市公式サイトまたはお住まいの区役所福祉課でご確認ください。掲載内容は確認時点のものであり、変更される場合があります。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
