insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"aichi-nagoya-elderly-diapers","status":"published","title":"日常生活用具の給付（紙おむつ等）","officialUrl":"https://www.kaigo-wel.city.nagoya.jp/view/wel/shiori/zaitaku/nichijyohin.html","topic":"elderly-diapers"}'::jsonb, 'pilot:aichi-nagoya-elderly-diapers:YWljaGktbmFnb3lhLWVsZGVybHktZGlhcGVyc3zm' from public.support_programs sp where sp.slug='aichi-nagoya-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kyoto' and m.slug = 'kyoto'), 'kyoto-kyoto-elderly-diapers', '京都市家族介護用品給付事業（紙おむつ等給付券）', '京都市が実施する在宅介護支援制度。要介護4・5と認定された65歳以上の高齢者を居宅で介護する市民税非課税世帯の家族に対し、紙おむつ等の介護用品と交換できる給付券（1枚5,000円相当）を交付する。交付枚数は申請月により段階的に減少する仕組み。', NULL, 'service', '京都市内に住所を有し現に居住する65歳以上で、要介護認定が要介護4または5であり、居宅（軽費老人ホーム・有料老人ホーム・サービス付き高齢者向け住宅を含む）において現に介護されている方の家族で、世帯が市民税非課税であるなど、公式サイトに示された要件に該当する可能性がある方が対象。詳細な所得判定や経過措置の適用可否は公式窓口での確認が必要。', '給付券1枚あたり5,000円相当。交付枚数は申請月によって異なる（令和8年度は例として4~5月申請で13枚、2~3月申請で3枚など、年度後半になるほど段階的に減少）。紙おむつ等の介護用品と交換できる仕組みで、現金給付ではない。', '公式ページに明確な申請期限の記載は確認できなかった。ただし毎年度申請が必要であるため、詳細は区役所窓口へ確認が必要。', '介護保険被保険者証記載住所地を管轄する各区役所・支所の健康長寿推進課（高齢介護保険担当）、または右京区は京北出張所（保健福祉第一担当）で申請する。毎年度の申請が必要。', '介護保険被保険者証の写し、世帯全員の市民税課税状況を証明する書類など。詳細・最新の必要書類は申請窓口で要確認。', FALSE, '京都市 各区役所・支所 健康長寿推進課（高齢介護保険担当）', '075-222-3800', 'https://www.city.kyoto.lg.jp/hokenfukushi/page/0000324770.html', 'https://www.city.kyoto.lg.jp/hokenfukushi/page/0000324770.html', '京都市：令和8年度京都市家族介護用品給付券の交付について', '2026-07-01', 'medium', ARRAY['給付券の交付枚数の申請月ごとの詳細な段階表（画像形式のため全容未確認）', '市民税非課税世帯の具体的な判定方法・経過措置の適用条件', '申請期限の有無（「毎年度申請が必要」とのみ記載）', 'オンライン申請の可否（公式ページからは確認できず、原則窓口申請とみられる）', '重度障害者向け紙おむつ給付（重度心身障害児者日常生活用具給付等事業）との併用可否・制度上の違い']::text[], '本情報は公式サイトの記載に基づく概括であり、支給の可否・金額・枚数を保証するものではありません。所得判定・要介護度の確認など詳細は必ず京都市の窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
