insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"kyoto-kyoto-elderly-diapers","status":"published","title":"京都市家族介護用品給付事業（紙おむつ等給付券）","officialUrl":"https://www.city.kyoto.lg.jp/hokenfukushi/page/0000324770.html","topic":"elderly-diapers"}'::jsonb, 'pilot:kyoto-kyoto-elderly-diapers:a3lvdG8ta3lvdG8tZWxkZXJseS1kaWFwZXJzfOS6' from public.support_programs sp where sp.slug='kyoto-kyoto-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'osaka'), 'osaka-osaka-elderly-diapers', '大阪市 介護用品支給事業（紙おむつ等の支給）', '大阪市内で在宅の要介護高齢者（要介護4・5、または要介護3で排尿・排便いずれかが全介助）を介護する家族介護者に対し、紙おむつ等の介護用品と引き換えられる給付券を交付する市の制度。要介護高齢者・介護者双方の世帯が市民税非課税であることが要件とされている。', NULL, 'service', '大阪市内に住み、在宅で要介護高齢者を介護している家族（介護者）で、要介護高齢者の要介護度が要介護4・5、または要介護3で認定調査票の「排尿」「排便」のいずれかが全介助とされている場合が対象となる可能性があります。要介護高齢者・介護者ともに世帯全員が市民税非課税であることが条件とされています。詳細な要件は公式資料・お住まいの区の窓口でご確認ください。', '支給決定後、対象介護用品（紙おむつ〔フラットタイプ・テープ止めタイプ・パンツタイプ〕、尿取りパッド、清拭剤、ドライシャンプー、使い捨て手袋、介護用スプーン・フォーク・箸、差し込み式便器・尿器、防水シーツ、口腔ケア用品、食事用エプロン、消臭剤、とろみ剤等）と引き換え可能な給付券（1枚あたり6,500円相当、年間最大12枚）が交付されるとされています。金額・枚数は変更される可能性があるため最新情報を公式でご確認ください。', '公式資料に明確な締切の記載は確認できませんでした。詳細はお住まいの区の窓口でご確認ください。', '要介護高齢者の住民登録がある区の区役所保健福祉課（高齢者福祉担当）で申請するとされています。申請後、決定されれば紙おむつ等の対象品目が記載されたカタログと給付券が交付される流れとされています。詳細な必要書類・受付時期は区の窓口でご確認ください。', '公式資料には具体的な必要書類の一覧が明記されていません。申請時の持ち物・書類はお住まいの区の保健福祉課へお問い合わせのうえご確認ください。', FALSE, 'お住まいの区の区役所保健福祉課（高齢者福祉担当）', '', 'https://www.city.osaka.lg.jp/fukushi/page/0000371237.html', 'https://www.city.osaka.lg.jp/fukushi/cmsfiles/contents/0000596/596293/R8.44-48.pdf', '介護保険制度のご案内（令和8年度版）大阪市福祉局', '2026-07-01', 'medium', ARRAY['制度の個別詳細ページ（旧URL）が確認日時点で404のため、officialUrlは公式PDF案内資料を採用している', '給付券の金額・年間枚数・所得要件・要介護度要件は公式資料時点のものであり、年度により変更される可能性がある', 'contactPhoneは資料に区ごとの直通番号が明記されていなかったため空欄とした。実際は各区保健福祉課の番号が必要', 'contactUrlは各区連絡先一覧への入口ページであり、保健福祉課の直通番号自体は掲載されていないため、各区ページでの再確認が必要']::text[], '本制度は所得（市民税非課税）・要介護度などの要件により対象とならない場合があります。申請すれば必ず受給できるものではなく、審査・認定を経て決定されます。最新の金額・要件・受付状況は必ず大阪市公式サイトまたはお住まいの区の窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
