insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"osaka-osaka-elderly-diapers","status":"published","title":"大阪市 介護用品支給事業（紙おむつ等の支給）","officialUrl":"https://www.city.osaka.lg.jp/fukushi/cmsfiles/contents/0000596/596293/R8.44-48.pdf","topic":"elderly-diapers"}'::jsonb, 'pilot:osaka-osaka-elderly-diapers:b3Nha2Etb3Nha2EtZWxkZXJseS1kaWFwZXJzfOWk' from public.support_programs sp where sp.slug='osaka-osaka-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'sakai'), 'osaka-sakai-elderly-diapers', '堺市高齢者紙おむつ給付事業', '堺市が実施する在宅の要介護高齢者向けの紙おむつ給付事業。市町村民税非課税世帯に属し、要介護4または5と判定された65歳以上の方を対象に、紙おむつと交換できる給付券を交付する制度です（詳細な要件・給付内容は公式サイトでご確認ください）。', NULL, 'service', '堺市内に居住し、65歳以上で要介護4または5と判定され、市町村民税非課税世帯に属する在宅高齢者が対象となる可能性があります（生活保護世帯・施設入所中・入院中の方等は対象外となる場合があります）。詳細は公式サイトでご確認ください。', '紙おむつと交換可能な給付券を月1枚交付（1枚あたり上限6,500円）。公式ページ本文には「給付決定のされた日の属する月からの給付」との記載があり毎月交付の運用と見られますが、実施要綱等との記載差の有無は要確認です。', '随時受付と見られますが、明確な締切記載は確認できませんでした。詳細は公式サイトでご確認ください。', '申請書（様式第1号）・調査書（様式第2号）等を、居住区の保健福祉総合センター地域福祉課（堺区・中区・東区・西区・南区・北区・美原区）に提出。堺市電子申請システムでも申請可能とされています。扶養義務者等による代理申請の記載もあります。詳細は公式サイトでご確認ください。', '申請書（様式第1号）、調査書（様式第2号）、内容変更・辞退時は様式第6号など。詳細は公式サイトまたは各区地域福祉課でご確認ください。', TRUE, '堺市健康福祉局長寿支援課', '072-228-8347', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kamiomutsu.html', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kamiomutsu.html', '高齢者紙おむつ給付事業 - 堺市', '2026-07-01', 'high', ARRAY['給付タイミング（実施要綱等で記載差がないか）', '前年度給付者の自動更新の有無・条件', '要介護4・5「に準じるものとして市長が認めた者」の具体的基準', '所得基準の詳細（非課税世帯の判定範囲）', '受付期間・締切の有無']::text[], '本情報は公式サイトの記載に基づく概括であり、対象者の該当・給付の可否を保証するものではありません。所得・要介護度等の詳細要件、給付額・給付タイミングの正確な運用は必ず堺市公式サイトまたは各区地域福祉課で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
