insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"osaka-sakai-elderly-diapers","status":"published","title":"堺市高齢者紙おむつ給付事業","officialUrl":"https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kamiomutsu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:osaka-sakai-elderly-diapers:b3Nha2Etc2FrYWktZWxkZXJseS1kaWFwZXJzfOWg' from public.support_programs sp where sp.slug='osaka-sakai-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hyogo' and m.slug = 'kobe'), 'hyogo-kobe-elderly-diapers', '紙おむつ支給事業（神戸市）', '神戸市が実施する在宅高齢者向けの紙おむつ・尿とりパッド支給事業。要介護4以上かつ世帯全員が市民税非課税等の条件を満たす方またはその介護家族を対象に、介護保険の給付対象外となる紙おむつ・尿とりパッドを現物支給する市独自制度（公式サイトで確認済み）。', NULL, 'service', '神戸市内に在住し在宅で介護を受けている高齢者で、介護保険の要介護認定が要介護4以上であり、世帯全員の市民税が非課税、かつ生活保護・中国残留邦人等支援給付を受給していない方、またはその方を介護する家族が対象です（神戸市の介護保険被保険者であることが前提）。', '年額25,000円〜100,000円分。申請受付時期により金額が異なります：4月1日〜6月15日受付は100,000円、6月30日〜9月15日受付は75,000円、9月30日〜12月15日受付は50,000円、1月5日〜3月12日受付は25,000円（公式サイトで確認、受付期間・金額は年度により変更の可能性があるため最新情報をご確認ください）。', '年度内に複数の受付期間が設定されており（例年4月1日〜6月15日、6月30日〜9月15日、9月30日〜12月15日、1月5日〜3月12日）、受付時期により支給額が異なります。正確な期間は年度により変動する可能性があるため公式サイトでご確認ください。', '担当のケアマネジャー等に相談のうえ、紙おむつ支給申請書を作成し、神戸市福祉局高齢福祉課（〒650-8570）へ郵送で提出します。', '紙おむつ支給申請書。成年後見人が手続きする場合は登記事項証明書等が必要となる場合があります。詳細は公式サイトでご確認ください。', FALSE, '神戸市福祉局高齢福祉課 紙おむつ支給事業担当', NULL, 'https://www.city.kobe.lg.jp/a39067/kurashi/registration/shinsei/koureisha/wh1306008.html', 'https://www.city.kobe.lg.jp/a39067/kurashi/registration/shinsei/koureisha/wh1306008.html', '神戸市：紙おむつ支給事業', '2026-07-01', 'high', '{}'::text[], '支給額の受付期間区分・対象要件（要介護度、所得要件等）は年度により変更される可能性があるため、必ず神戸市公式サイトまたは担当窓口で最新情報をご確認ください。申請すれば必ず支給を受けられるとは限らず、審査・要件確認が必要です。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
