insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"hyogo-kobe-elderly-diapers","status":"published","title":"紙おむつ支給事業（神戸市）","officialUrl":"https://www.city.kobe.lg.jp/a39067/kurashi/registration/shinsei/koureisha/wh1306008.html","topic":"elderly-diapers"}'::jsonb, 'pilot:hyogo-kobe-elderly-diapers:aHlvZ28ta29iZS1lbGRlcmx5LWRpYXBlcnN857SZ' from public.support_programs sp where sp.slug='hyogo-kobe-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hiroshima' and m.slug = 'hiroshima'), 'hiroshima-hiroshima-elderly-diapers', '高齢者在宅介護用品の支給（広島市）', '広島市が実施する在宅の要介護高齢者向け介護用品支給事業。要介護4・5と認定され市民税非課税世帯等に属する在宅の高齢者を対象に、紙おむつ・尿とりパッド・介護用シーツ・おしりふき・使い捨て手袋を月額上限の範囲内で現物支給する制度。公式サイトで確認できる情報をもとに概括しており、詳細な要件は必ず公式ページ・区役所窓口で確認してください。', NULL, 'service', '広島市内に住所があり在宅で生活し、介護保険の要介護認定で要介護4または5と認定され、市民税非課税世帯（生活保護・支援給付受給世帯を除く）に属する高齢者、またはその方を介護する市内在住の家族が対象となる可能性があります。同居の場合は原則同一世帯とみなされる旨が公式サイトに記載されています。詳細な適用条件は公式で確認してください。', '月額6,500円の範囲内で、紙おむつ・尿とりパッド・介護用シーツ・おしりふき・使い捨て手袋を、利用者が選んだ事業者経由で現物支給（配達）する仕組みと案内されています。金額や品目の詳細は公式ページ・申請窓口で要確認です。', '通年で随時申請可能と見られますが、公式ページ上に明示的な締切記載は確認できませんでした。', '申請書（広島市高齢者在宅介護用品支給申請書等）を、居住区の区役所厚生部福祉課高齢介護係の窓口に提出する方法が案内されています。申請書は公式サイトからダウンロード可能とされています。オンライン申請の可否は公式ページ上で明記が確認できませんでした。', '申請書のほか、要介護認定・課税状況等を確認できる書類が必要となる可能性があります。詳細は区役所窓口・公式サイトで確認してください。', FALSE, '広島市 健康福祉局高齢福祉部（居住区の区役所厚生部福祉課高齢介護係が窓口）', '082-504-2145（健康福祉局高齢福祉部）／各区役所窓口は区ごとに異なる（例：中区厚生部福祉課 082-504-2570）', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015439.html', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015439.html', '高齢者在宅介護用品の支給｜広島市公式ウェブサイト', '2026-07-01', 'high', ARRAY['月額支給上限6,500円の内訳・品目ごとの詳細', 'オンライン申請の可否（公式ページ上で明記未確認）', '申請の締切・受付時期', '所得（市民税非課税）の具体的な判定基準', '介護者（家族）が申請主体となる場合の要件詳細', '重度障害者向けには別途『日常生活用具の給付』事業（紙おむつ等を含む排せつ管理支援用具、令和7年4月から対象拡大、所得に応じ月額9,300～37,200円の上限負担あり）が存在するが、本programは高齢者・要介護者向け制度のみを対象としており、障害者向け制度の詳細は別途要確認']::text[], '本情報は公式サイトの記載を要約したものであり、最終的な支給の可否・金額・要件は必ず広島市（居住区の区役所福祉課）に確認してください。本サイトが申請を代わりに行うすることはありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
