insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"hiroshima-hiroshima-elderly-diapers","status":"published","title":"高齢者在宅介護用品の支給（広島市）","officialUrl":"https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015439.html","topic":"elderly-diapers"}'::jsonb, 'pilot:hiroshima-hiroshima-elderly-diapers:aGlyb3NoaW1hLWhpcm9zaGltYS1lbGRlcmx5LWRp' from public.support_programs sp where sp.slug='hiroshima-hiroshima-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'kitakyushu'), 'fukuoka-kitakyushu-elderly-diapers', '北九州市 おむつ給付サービス', '北九州市が実施する在宅の要介護高齢者向けの紙おむつ等現物給付サービス。要介護認定を受け、市民税非課税世帯に属するなど一定の条件を満たす方を対象に、紙おむつ・尿取りパッド・介護用シーツを毎月自宅へ配達する制度。詳細な対象条件・費用は公式サイトでの確認が必要。', NULL, 'service', '北九州市内に住み、介護保険の要介護認定を受けている方のうち、原則要介護3以上と認定され、市民税非課税世帯に属し、失禁等のため常時在宅でおむつを必要とする方が対象となる可能性があります（要介護4・5以外の新規利用者は訪問調査での判定が必要な場合があります。公式で要確認）。', '紙おむつ・尿取りパッド・介護用シーツを毎月自宅に配達。自己負担は助成限度額内の利用額の1割で、要介護3は月6,000円、要介護4は月6,500円、要介護5は月7,000円が限度額とされていますが、最新の金額・条件は公式サイトで確認してください。生活保護世帯は自己負担なしとされています。', '', 'お住まいの区の区役所（保健福祉課高齢者・障害者相談係）へ申し込みます。身体状況等を検討のうえ利用が決定され、事業者から自宅への配達が行われます。', '', FALSE, '各区役所 保健福祉課 高齢者・障害者相談係', '', 'https://www.city.kitakyushu.lg.jp/kurashi/menu01_0315.html', 'https://www.city.kitakyushu.lg.jp/contents/924_11183.html', 'おむつ給付サービス - 北九州市', '2026-07-01', 'high', ARRAY['自己負担限度額（要介護度別の月額）は最新の公式情報で要確認', '対象となる要介護度の下限（原則要介護3以上とされるが例外条件の有無は要確認）', '支給される紙おむつ等の数量・種類の詳細', '市民税非課税世帯以外の世帯の取り扱い']::text[], '本制度の詳細な対象条件・自己負担額・支給内容は変更される場合があるため、必ず北九州市公式サイトまたは各区役所窓口で最新情報をご確認ください。申請すれば必ず利用できるとは限りません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
