insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"fukuoka-kitakyushu-elderly-diapers","status":"published","title":"北九州市 おむつ給付サービス","officialUrl":"https://www.city.kitakyushu.lg.jp/contents/924_11183.html","topic":"elderly-diapers"}'::jsonb, 'pilot:fukuoka-kitakyushu-elderly-diapers:ZnVrdW9rYS1raXRha3l1c2h1LWVsZGVybHktZGlh' from public.support_programs sp where sp.slug='fukuoka-kitakyushu-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'fukuoka'), 'fukuoka-fukuoka-elderly-diapers', '福岡市 おむつサービス（紙おむつ購入費助成）', '福岡市が実施する在宅高齢者向けの紙おむつサービス。要介護3〜5と認定され、寝たきり等によりおむつが必要な在宅の方を対象に、紙おむつ購入費用の一部を所得段階に応じて助成する制度（公式で確認）。', NULL, 'subsidy', '福岡市の介護保険被保険者で要介護3〜5と認定され、寝たきりなどによりおむつが必要な在宅の方が対象となる可能性があります（入院中・短期入所（ショートステイ）中は対象外）。詳細な認定基準は公式で確認してください。', '所得段階に応じて助成率0％〜100％、月額上限は0円〜6,000円の範囲で設定されている模様です（現物支給ではなく、利用者が事業者から紙おむつを購入し、その費用の一部が助成される仕組み）。具体的な段階・金額は公式ページの一覧表で確認してください。', '', '各区保健福祉センター福祉・介護保険課の窓口または郵送で申請するほか、マイナポータルからの電子申請（区ごと）も可能とされています。申請には地域支援事業サービス利用申込書、利用内訳書、介護保険被保険者証等が必要とされる模様です。', '地域支援事業サービス利用申込書、利用内訳書、介護保険被保険者証等（公式ページの記載に基づく。詳細は要確認）。', TRUE, '各区保健福祉センター福祉・介護保険課', '', 'https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020105.html', 'https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020105.html', '福岡市 おむつサービス', '2026-07-01', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は福岡市公式サイトの記載に基づく概括であり、所得段階・助成率・上限額・対象要件は個々の状況により異なります。必ず福岡市公式サイトまたは各区保健福祉センターで最新情報をご確認ください。申請すれば必ず受給できることを保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
