insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"fukuoka-fukuoka-elderly-diapers","status":"published","title":"福岡市 おむつサービス（紙おむつ購入費助成）","officialUrl":"https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020105.html","topic":"elderly-diapers"}'::jsonb, 'pilot:fukuoka-fukuoka-elderly-diapers:ZnVrdW9rYS1mdWt1b2thLWVsZGVybHktZGlhcGVy' from public.support_programs sp where sp.slug='fukuoka-fukuoka-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sapporo.jp/kaigo/k100citizen/k160dokuji.html', 'WebFetchでofficialUrlを検証。ページ「介護保険サービス以外に札幌市が行っている高齢者支援（地域支援事業など）」内の『おむつサービス』の記載は、一次調査のresearchNote・program内容と完全に一致：対象（在宅40歳以上・札幌市内居住・要介護4〜5で排尿排便全介助、または要介護3で認知症高齢者日常生活自立度III以上かつ排尿排便全介助）、支給内容（月1回・上限6,500円・宅配）、自己負担（1割、生活保護受給者無料）、申請窓口（各区役所保健福祉課）、受付状況（現行）。(a)到達OK (b)city.sapporo.jp＝許可ホストOK (c)紙おむつ支給制度そのものの当該市ページでOK、対象市は札幌市で一致 (d)現行サービスで年度終了の記載なし (e)市独自の地域支援事業として明記されており国/都道府県制度の誤認なし (f)targetPeopleは「〜可能性があります」等の非断定表現で対象の一部を全体化していない (g)重度障がい者向け別制度(omutuyouryo202504.pdf)はcategorySlugs/topicSlugsに含めておらず、混' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hokkaido' and m.slug='sapporo' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sendai.jp/hokatsushien/kurashi/kenkotofukushi/korenokata/zaitaku/fukushi/kaigoyohin.html', 'WebFetchでofficialUrlを検証済み。ページ内容は一次調査のprogram記載と完全に整合。仙台市公式ドメイン(city.sendai.jp)、要介護4・5かつ市民税非課税世帯を対象とした介護用品給付事業（使い捨ておむつ・おむつカバー・尿とりパッド・失禁シーツの現物給付、年間限度額7万5千円）を仙台市独自の制度として確認。最終更新日2024年5月2日で受付終了の記載なし、現行制度と判断。障害者向け日常生活用具給付とは区別されており複数制度の混在なし。断定を避けた表現も維持されている。是正の必要なし。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='miyagi' and m.slug='sendai' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.saitama.lg.jp/002/003/003/002/005/p064031.html', 'WebFetchでofficialUrlに到達し検証。(a)到達可能 (b)ホストは city.saitama.lg.jp で許可ホスト・さいたま市公式 (c)紙おむつ支給事業そのものの当該市ページ (d)最終更新日2026年6月3日で現行、受付終了の記載なし (e)「市独自事業」と明記されており国・県制度の誤認ではない (f)対象要件（65歳以上・要介護3〜5、要介護3は排尿排便介助等が必要な場合限定、所得段階第1〜5・滞納なし・生活保護/施設入所/長期入院除外）はprogram.targetPeopleに概括として記載され「詳細は公式ページ・区役所で確認」と非断定 (g)重度障害者向けの別制度は含まれておらず単一制度のみ (h)金額・支給枚数・要介護度の数値は公式ページと一致し、断定的な保証表現もなし。prefectureSlug="saitama"・municipalitySlug="saitama"・slug="saitama-saitama-elderly-diapers"を確認、いずれも妥当。是正の必要なし。programは一次調査のものをそのまま採用。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/diaper.html', 'WebFetchでofficialUrl(https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/diaper.html)に到達し検証。(a)到達可、(b)千葉市公式ホスト(city.chiba.jp)でFAQ専用ドメインではない、(c)紙おむつ支給/助成そのものの当該市ページ（「おむつ給付等事業（高齢者）」）で千葉市の制度、(d)更新日2025年10月14日と明記され現行ページ、(e)千葉市独自事業であり国/都道府県の一般説明ではない、(f)対象者（要介護1-5・常時失禁状態・在宅・市民税非課税世帯・生活保護等非受給・障害者向け給付非受給）が一次調査のtargetPeopleと整合し一部を全体と誤記していない、(g)高齢者向け制度と障害者向け制度は別制度としてsummaryで区別済みで1件に混同していない、(h)支給額（要介護1-3:月額4,000円＝市9割3,600円+利用者1割400円、要介護4-5:月額8,000円＝市9割7,200円+利用者1割800円）はWebFetch結果と一次調査のbenefitAmountTex' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/fukushi-kaigo/koreisha-kaigo/kaigohoken-igai-service/zaitaku-yoengo-shien/kourei-omutsu.html', 'WebFetchでofficialUrlを直接検証済み。(a)到達可（HTTP 200相当で本文取得）。(b)横浜市公式ドメイン(city.yokohama.lg.jp)、パンくずリスト「横浜市トップページ＞健康・医療・福祉＞福祉・介護＞高齢者福祉・介護＞介護保険以外のサービス」およびフッター「横浜市役所」情報で公式性を確認。(c)紙おむつ支給/助成そのものの当該市ページであり、他市の制度ではない。(d)最終更新日は2026年6月18日と新しく、受付終了・古い年度情報ではない。(e)国・都道府県の一般制度説明ではなく横浜市独自事業として明確。(f)対象者要件（要介護4-5、または要介護1-3で福祉保健センター長が認めた場合、かつ生活保護受給世帯等または市民税非課税世帯）は一次調査の記載と一致し、対象の一部を全体と誤記していない。(g)高齢者向け紙おむつ給付事業という単一制度で、障害者向け別制度と混同していない（一次調査でも障害者向けは別枠として言及のみで本制度には混入させていない）。(h)金額（要介護4-5=月額8,000円/4単位、要介護1-3=月額6,000円/3単位、自己負担1割' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='yokohama' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kawasaki.jp/350/page/0000022608.html', 'WebFetchでofficialUrl(https://www.city.kawasaki.jp/350/page/0000022608.html)に到達確認。許可ホスト(city.kawasaki.jp)一致。ページは川崎市独自の「紙おむつ等介護用品の給付」制度で、国・県制度の説明ではなく市独自事業と明記。対象(65歳以上要介護3～5、または40～64歳要介護3～5かつ初老期認知症相当。施設入所・長期入院者は対象外)、給付額(月額6,000円限度額、令和8年4月改定後)、利用者負担率(生活保護0%/減免5%/非課税10%/課税20%)、申請窓口(各区役所高齢・障害課、オンライン申請対応)、担当課(健康福祉局高齢者在宅サービス課 044-200-2911)を確認、一次調査の記載と整合。ページ最終更新日は2026年4月23日で現行(古い年度/受付終了の兆候なし)。複数制度の混在や対象の一部を全体と誤認している箇所もなし。金額・負担率・要介護度の細部はdisclaimerNoteとuncertainFieldsで「公式で確認」を促しており断定回避も適切。是正不要のためprogramは一次' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='kawasaki' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026635/korei_shien/1006388.html', 'WebFetchでofficialUrlに到達確認。(a)到達=OK。(b)ホストはcity.sagamihara.kanagawa.jpで許可ホスト内。(c)ページタイトルは「紙おむつ等の支給」で、当該市自身の紙おむつ支給制度そのもの（相模原市で一致、他市の誤記載なし）。(d)受付終了・古い年度を示す記載はなくフェッチ結果は現行制度として提示。(e)国や県の一般制度説明ではなく相模原市独自事業と明記されている。(f)対象は「60歳以上ねたきり高齢者(要介護4・5)/認知症高齢者」と「身体障害者手帳・療育手帳所有の在宅障害者」の複数対象群を並記しており、一次調査のtargetPeopleは両方を反映済みで一部のみを全体化していない。(g)フェッチ結果でも単一の紙おむつ支給制度のみが記載されており、複数制度の混在は見られない。(h)FORBIDDEN文言・断定的な金額/要介護度の記載はなく、支給内容は現物支給（パンツ型・フラット型・テープ型・子供用テープ型・尿とりパッド）、年6回、無料という概括にとどめ「公式で確認」を維持。所得制限文言はフェッチ結果で「本人及び世帯に市民税課税者がいる場' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='sagamihara' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.niigata.lg.jp/iryo/korei/zaitakukaigo/kamiomutsu.html', 'WebFetchでofficialUrlを検証済み。到達可能・.lg.jp公式ホスト・新潟市独自の「紙おむつ支給事業」ページであることを確認。対象者要件（40歳以上・要介護1〜5・自立度B以上等・本人非課税段階1〜5）、支給枚数（非課税世帯段階1〜3で要介護1〜3はパンツ60枚/平型200枚、要介護4〜5は90枚/300枚、本人非課税段階4・5は全要介護度で30枚/100枚、いずれも毎月支給）、問い合わせ先（各区健康福祉課高齢介護担当／福祉部高齢者支援課025-226-1295）が一次調査のprogram内容と整合。国制度でなく市独自制度と明記あり。最終更新2021年2月10日と古いが受付終了の記載はなし。複数制度の混在や対象の一部を全体と誤記する問題は見られない。是正不要のためprogramは一次調査の内容をそのまま採用。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='niigata' and m.slug='niigata' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.shizuoka.lg.jp/s2837/s002726.html', 'WebFetchでofficialUrl(https://www.city.shizuoka.lg.jp/s2837/s002726.html)を検証。(a)到達可能 (b)静岡市公式ドメイン(city.shizuoka.lg.jp)で許可ホストに一致 (c)当該ページは静岡市の「高齢者紙おむつ支給制度」そのものであり、対象=静岡市（他市との取り違えなし） (d)最終更新2026-06-27で現行ページ、廃止・受付終了の記載はなし（ただしWebFetch要約は「2027年3月31日までに申請」という期限記載を報告しており、一次調査の「締切不明」との間に差異あり。二次要約の信頼性を考慮し、programのapplicationDeadlineTextは曖昧な記載のまま維持し断定を避ける） (e)国・県制度の一般説明ではなく市独自制度であることが記載から確認できる (f)対象要件（要介護4以上が主対象、要介護1〜3は条件付き、所得要件、在宅要件）を一部のみでなく全体として概括している (g)障害者向け類似制度とは別ページ・別事業として区別されており、1件に混在させていない (h)金額・要介' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='shizuoka' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/zaitaku/omutsu.html', 'WebFetchでofficialUrlを直接取得し、一次調査の内容と全項目一致を確認した。(a)到達可能 (b)city.hamamatsu.shizuoka.jpは浜松市公式ドメイン（city.*パターン、FAQ専用ドメインでない）で許可ホスト適合 (c)紙おむつ支給そのものを扱う浜松市固有ページ（他市の誤認なし） (d)ページ更新日2025年4月14日、「毎年度2月末頃」等の経常的記述で失効情報ではない (e)中央・浜名・天竜の各福祉事業所という浜松市独自の窓口が明記されており、国・県制度の誤認ではなく市独自制度と確認 (f)要介護4・5かつ介護者・被介護者双方が市民税非課税世帯という条件が対象の一部ではなく全体として正確に記載されている (g)重度障害者向け別制度（紙おむつ購入費助成）はprogramの主要フィールドには混入されておらず、summary/uncertainFieldsへの注記に留めており複数制度の混在なし (h)benefitAmountText・targetPeopleとも「〜されています」「〜可能性があります」という非断定的表現でFORBIDDEN表現なし。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='hamamatsu' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.kaigo-wel.city.nagoya.jp/view/wel/shiori/zaitaku/nichijyohin.html', 'officialUrl（種目一覧紹介ページ）にWebFetchで到達確認。ページ本文には「紙おむつ」の直接記載はなかったが、同ページからリンクされる同一公式ドメインのPDF（kaigo-wel.city.nagoya.jp/_files/00137874/R804ichiran.pdf、令和8年4月版）をダウンロードしpdftotext -layoutで全文抽出・直接検証したところ、種目「紙おむつ等」が実在し、対象者要件は【ぼうこう機能障害の方】①治療で軽快見込みのないストーマ周辺皮膚びらん等でストーマ用装具装着不可、②先天性疾患（先天性鎖肛除く）起因の神経障害による高度排尿機能障害、【直腸機能障害の方】③同様のストーマ装着不可要件、④先天性疾患起因の高度排便機能障害、⑤先天性鎖肛の肛門形成術に起因する高度排便機能障害、【肢体不自由の方】⑥脳原性運動機能障害により排尿・排便の意思表示が困難で発現年齢6歳未満・申請時3歳以上、の6要件で構成されており、一次調査のtargetPeople記述と完全に一致することを確認した。給付基準額・耐用年数欄は「―」（金額記載なし）で一次調査のbenef' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='aichi' and m.slug='nagoya' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kyoto.lg.jp/hokenfukushi/page/0000324770.html', 'WebFetchでofficialUrl(0000331377)を検証したところ、これは「家族介護用品給付事業における経過措置」専用の案内ページであり、令和5年度に均等割減免を受けていた世帯が令和6年度以降課税対象となった場合の特例措置についてのページだった。通常の制度概要（対象者要件・給付枚数表・申請窓口）を説明するメインページではなかったため不適切と判断。researchNoteが言及していたもう一方の候補ページ(0000324770)を検証したところ、こちらが「令和8年度京都市家族介護用品給付券の交付について」という現行のメイン案内ページであり、対象者（65歳以上・要介護4-5・居宅介護・市民税非課税世帯家族）、給付内容（1枚5,000円相当、申請月により13枚~3枚等の変動）、申請窓口（各区役所・支所の健康長寿推進課、右京区は京北出張所）、必要書類（介護保険被保険者証写し、市民税課税状況証明書）を包括的に記載しており、2026-04-01掲載の令和8年度版で現行。京都市保健福祉局健康長寿のまち・京都推進室介護ケア推進課が実施主体であることも明記されており、市独自の在宅介護支援制' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kyoto' and m.slug='kyoto' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.osaka.lg.jp/fukushi/cmsfiles/contents/0000596/596293/R8.44-48.pdf', 'officialUrl（PDF）をダウンロードしテキスト抽出して直接検証した。WebFetchツールは同PDFのメタデータしか読めなかったため、curlで取得しpdftotextでレイアウト保持抽出を行い、本文全文を確認した。抽出結果は一次調査の記載と完全に一致：「3.介護用品支給事業」として『在宅で介護が必要な方を介護する家族の負担を軽減するため、紙おむつなどの介護用品を支給します』と明記。支給品目（紙おむつ3タイプ、尿取りパッド等）、支給方法（給付券1枚6,500円相当・年間最大12枚＋カタログ交付）、対象者（要介護4・5または要介護3で排尿・排便いずれか全介助を介護する市内在住家族、要介護者・介護者ともに世帯全員市民税非課税）が一次調査のprogram内容と完全一致した。文書は「令和8年度版」（=2026年度、現行）の大阪市福祉局公式冊子で、隣接項目「2.日常生活用具給付事業」（自動消火器・電磁調理器のみ、紙おむつ対象外）とは明確に別項目として区別されている。旧URL（0000370480.html）は実機で404を再確認。ホストはcity.osaka.lg.jpで許可ホストに適' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='osaka' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/life_support/kamiomutsu.html', 'WebFetchで公式URL(city.sakai.lg.jp、堺市公式ドメイン)に到達し内容確認。堺市高齢者紙おむつ給付事業のページであり、65歳以上・要介護4/5・市民税非課税世帯という対象要件、月1枚(上限6,500円)の給付券交付、区役所地域福祉課(堺区・中区・東区・西区・南区・北区・美原区)申請、健康福祉局長寿支援課(072-228-8347)問い合わせ、いずれも一次調査のprogram内容と一致。最終更新日2026年1月13日で古い年度・受付終了の兆候なし。国/都道府県制度の混入、他市との混同、複数制度の混在は見られない。給付タイミングについては公式ページ本文に「給付決定のされた日の属する月からの給付」との記載があり毎月交付の運用と読めるが、実施要綱側の記載差異は今回のWebFetchでは再検証できていないため、一次調査のuncertainFieldsに残した「給付タイミングの表現差」はそのまま維持するのが妥当。program本文は断定を避け「公式サイトでご確認ください」を付した概括表現になっており、対象の一部を全体化する記述や複数制度の混在もないため是正不要。covera' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='sakai' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kobe.lg.jp/a39067/kurashi/registration/shinsei/koureisha/wh1306008.html', 'WebFetchでofficialUrlを検証：(a)到達可、(b)city.kobe.lg.jp本体ページで許可ホスト・FAQ専用ドメインではない、(c)紙おむつ支給事業そのものの神戸市ページ（他市の混同なし）、(d)最終更新日2026-02-20と明記され現行ページと確認、(e)国・県制度の一般説明ではなく神戸市独自事業と明記、(f)対象の一部を全体化していない（要介護4以上・世帯全員市民税非課税・生活保護/中国残留邦人等支援給付非受給という複数要件がすべて明記）、(g)障害者向け日常生活用具費支給制度とは別物として区別済み・混在なし、(h)断定的な言い切りは避け「公式で確認」の形。一次調査で不確実とされていた申請時期別金額（4-6月10万円/7-9月7.5万円/10-12月5万円/1-3月2.5万円）はWebFetchで正確な受付期間（4/1-6/15、6/30-9/15、9/30-12/15、1/5-3/12）とともに確定。targetPeopleも要介護4以上・世帯全員市民税非課税・生活保護等非受給という具体的要件が確認できた。prefectureSlug=hyogo、mun' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.okayama.jp/0000017087.html', '敵対的検証の結果、一次調査の結論（not_found_on_official_site）を支持する。追加でWebFetchによる直接検証を4件実施：
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014902/1025759/1025760/1015439.html', 'WebFetchでofficialUrlを実機検証。(a)到達可 (b)city.hiroshima.lg.jpの許可ホストで広島市公式 (c)紙おむつ等支給の当該市ページ (d)受付終了等の記載なし・現行制度 (e)ページ本文に「広島市独自の在宅福祉サービスで、介護保険の給付とは別の事業」と明記されており国/県制度の誤認ではない (f)対象要件（要介護4/5・市民税非課税世帯・在宅）は一次調査のtargetPeopleと一致し部分を全体化していない (g)障害者向け「日常生活用具の給付」は別事業として一次調査でも意図的に除外されており混在なし (h)金額(月額6,500円の範囲内)・対象は概括的表現かつ「公式で確認」の免責が付されている。すべての検証項目をクリアしたためprogramは是正なしでそのまま採用。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kitakyushu.lg.jp/contents/924_11183.html', 'WebFetchでofficialUrl(https://www.city.kitakyushu.lg.jp/contents/924_11183.html)に到達し内容を検証した。(a)到達OK (b)city.kitakyushu.lg.jp＝北九州市公式の許可ホストでFAQ専用ドメインではない (c)当該市の「おむつ給付サービス」制度そのもののページで北九州市の記載と一致 (d)更新日2025年12月1日と表示され現行ページ、受付終了の兆候なし (e)市独自の在宅高齢者向け現物給付制度であり国/都道府県の一般施策の誤認ではない (f)対象条件（市民税非課税世帯・要介護3以上を原則としつつ要介護4/5以外でも訪問調査で該当すれば対象となりうる旨）が一次調査のtargetPeopleと整合し、対象の一部を全体と書いていない (g)高齢者向けおむつ給付サービス1件のみを扱っており、重度障害者向け日常生活用具給付等事業など別制度と混在していない (h)自己負担限度額（要介護3=6,000円/要介護4=6,500円/要介護5=7,000円、生活保護世帯は自己負担なし）はfetch結果と一致' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='kitakyushu' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.fukuoka.lg.jp/fukushi/oldage-welfare/health/00/03/3-020105.html', 'WebFetchでofficialUrlに到達し内容を確認。(a)到達可 (b)city.fukuoka.lg.jp＝福岡市公式の許可ホスト (c)紙おむつサービス（購入費助成）そのものの福岡市ページ (d)ページ更新日2026年5月20日で現行制度と判断できる (e)福岡市独自の事業であり国・県制度の一般説明ではない (f)対象は「要介護3〜5・在宅」で一次調査のtargetPeopleと一致し、一部を全体と誤記していない (g)複数制度を混在させていない（障がい者向け日常生活用具給付は別ページとして区別済み） (h)金額（所得段階0〜100%・月額上限0〜6,000円）は一次調査の記載と一致し、断定を避けた表現（「模様です」等）になっている。よってcoverage=found・ok=trueで確定。programは一次調査の内容をそのまま採用（是正不要）。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='fukuoka' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'needs_review', '2026-07-01', 'https://www.city.kumamoto.jp/kiji00369822/index.html', '敵対的検証の結果、officialUrlは到達可能かつ熊本市公式ドメイン(city.kumamoto.jp)であることは確認できたが、WebFetchで本文を精読したところ、このページは令和8年度(2026年度)の『事業者募集』ページであり、対象は参加を希望する法人・事業協同組合であって、利用者(高齢者・家族)向けの紙おむつ支給制度の説明ページではないことが判明した。掲載内容は事業者の参加要件(10品目取扱い・法人格・熊本市内拠点・税滞納なし等)、提出期限(令和8年3月31日)、提出先(高齢福祉課在宅支援班)のみで、対象者の要介護度・所得要件、支給限度額、自己負担、利用者の申請窓口・方法についての記載は一切ない。高齢福祉課のページ一覧(list02385.html)を確認しても、他に利用者向け案内ページへのリンクは見当たらなかった。実施規則PDF(UploadFileDsp.aspx経由)や過去年度(令和6年度)の詳細ページ(hpKiji/pub/detail.aspx経由)へのアクセスも試みたが、いずれも404で本文取得できなかった。制度自体(『熊本市高齢者介護用品支給事業』という名' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kumamoto' and m.slug='kumamoto' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
